@import '../../utils/control-inactive.css';
@import '../../utils/typography.css';

.input-container {
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-050);
  width: 100%;
}

.wrapper {
  width: 100%;
  height: var(--dimension-size-400);
  display: flex;
  align-items: center;
  background-color: var(--color-background-primary);
  border-radius: var(--dimension-radius-075);
  box-shadow: var(--effect-elevation-depressed-sm);
  box-sizing: border-box;
}

.wrapper:focus-within {
  box-shadow: inset 0 0 0 1.25px var(--color-foreground-bold-brand);
}

.wrapper--error {
  box-shadow: inset 0 0 0 1.25px var(--color-border-bold-negative);
}

.wrapper--error:focus-within {
  box-shadow: inset 0 0 0 1.25px var(--color-border-bold-negative);
}

.row {
  display: flex;
  align-items: center;
  width: 100%;
  height: 100%;
  gap: var(--dimension-space-050);
}

.native-input {
  flex: 1;
  min-width: 0;
  height: 100%;
  padding: 0 var(--dimension-space-100);
  background: transparent;
  border: none;
  outline: none;
  font-family: inherit;
  color: var(--color-foreground-primary);
  border-radius: var(--dimension-radius-075);
  -webkit-appearance: none;
  appearance: none;
}

/* Inactive: host `.ds-control-inactive` (25% opacity). Native disabled still blocks input. */
.native-input:disabled {
  cursor: not-allowed;
}

.native-input::placeholder {
  color: var(--color-foreground-secondary);
}

.native-input:focus::placeholder {
  color: var(--color-foreground-tertiary);
}

.native-input[type='search']::-webkit-search-cancel-button,
.native-input[type='search']::-webkit-search-decoration {
  display: none;
}

.clear-btn {
  flex-shrink: 0;
  margin-right: var(--dimension-space-050);
  padding: var(--dimension-space-050);
  border: none;
  background: none;
  cursor: pointer;
  color: var(--color-foreground-secondary);
  border-radius: var(--dimension-radius-050);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
}

.clear-btn:hover {
  background-color: var(--color-interaction-hover);
}

.suffix {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  margin-right: var(--dimension-space-050);
}

.suffix:empty {
  display: none;
}

import { EventEmitter } from '@stencil/core';
export type InputType = 'text' | 'email' | 'tel' | 'url' | 'search' | 'password';
export declare class Input {
    el: HTMLElement;
    private generatedId;
    private errorId;
    value: string;
    placeholder: string | undefined;
    type: InputType;
    isInactive: boolean;
    autoFocus: boolean;
    error: boolean;
    errorMessage: string | undefined;
    /** Associates the internal input with an external <label>. */
    inputId: string | undefined;
    ariaLabel: string | undefined;
    ariaLabelledby: string | undefined;
    ariaDescribedby: string | undefined;
    dsChange: EventEmitter<string>;
    dsClear: EventEmitter<void>;
    setFocus(): Promise<void>;
    private handleInput;
    private handleClear;
    render(): any;
}

import { AttachInternals, Component, Prop, Event, EventEmitter, Element, Method, Watch, h, Host } from '@stencil/core';

export type InputType = 'text' | 'email' | 'tel' | 'url' | 'search' | 'password';

let idCounter = 0;

@Component({
  tag: 'ds-input',
  styleUrl: 'Input.css',
  scoped: true,
  formAssociated: true,
})
export class Input {
  @Element() el!: HTMLElement;
  @AttachInternals() internals!: ElementInternals;

  private generatedId = `ds-input-${++idCounter}`;
  private errorId = `${this.generatedId}-error`;

  @Prop({ mutable: true }) value: string = '';
  @Prop() name: string | undefined;
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop({ reflect: true }) required: boolean = false;
  @Prop() requiredMessage: string = 'This field is required.';
  @Prop() clearLabel: string = 'Clear';
  @Prop() placeholder: string | undefined;
  @Prop() type: InputType = 'text';
  @Prop() isInactive: boolean = false;
  @Prop() autoFocus: boolean = false;
  @Prop() error: boolean = false;
  @Prop() errorMessage: string | undefined;
  /** Associates the internal input with an external <label>. */
  @Prop() inputId: string | undefined;
  @Prop({ attribute: 'aria-label' }) ariaLabel: string | null = null;
  @Prop({ attribute: 'aria-labelledby' }) ariaLabelledby: string | undefined;
  @Prop({ attribute: 'aria-describedby' }) ariaDescribedby: string | undefined;

  @Event() dsChange!: EventEmitter<string>;
  @Event() dsClear!: EventEmitter<void>;

  private initialValue = '';

  componentWillLoad() {
    this.initialValue = this.value;
    this.syncFormValue();
  }

  @Watch('value')
  @Watch('disabled')
  @Watch('isInactive')
  @Watch('required')
  syncFormValue() {
    const inactive = this.isInactive || this.disabled;
    this.internals.setFormValue(inactive ? null : this.value);
    const missing = this.required && !inactive && this.value.length === 0;
    this.internals.setValidity(missing ? { valueMissing: true } : {}, missing ? this.requiredMessage : '');
  }

  formDisabledCallback(disabled: boolean) {
    this.disabled = disabled;
  }

  formResetCallback() {
    this.value = this.initialValue;
  }

  formStateRestoreCallback(state: string | File | FormData | null) {
    this.value = typeof state === 'string' ? state : '';
  }

  @Method()
  async setFocus() {
    this.el.querySelector('input')?.focus();
  }

  private handleInput = (e: Event) => {
    this.value = (e.target as HTMLInputElement).value;
    this.dsChange.emit(this.value);
  };

  private handleClear = () => {
    this.value = '';
    this.dsChange.emit('');
    this.dsClear.emit();
    this.el.querySelector('input')?.focus();
  };

  render() {
    const inputId = this.inputId ?? this.generatedId;
    const inactive = this.isInactive || this.disabled;
    const showClear = this.type === 'search' && this.value.length > 0 && !inactive;
    const showError = this.error && Boolean(this.errorMessage);

    const describedBy = [
      this.ariaDescribedby,
      showError ? this.errorId : undefined,
    ].filter(Boolean).join(' ') || undefined;

    return (
      <Host class={{ 'input-container': true, 'ds-control-inactive': inactive }}>
        <div class={{ wrapper: true, 'wrapper--error': this.error }}>
          <div class="row">
            <input
              type={this.type}
              id={inputId}
              value={this.value}
              placeholder={this.placeholder}
              disabled={inactive}
              required={this.required}
              autoFocus={this.autoFocus}
              class="native-input ds-text--body-medium ds-text--regular"
              aria-label={this.ariaLabel}
              aria-labelledby={this.ariaLabelledby}
              aria-describedby={describedBy}
              aria-invalid={this.error || undefined}
              onInput={this.handleInput}
            />
            {showClear && (
              <button
                type="button"
                class="clear-btn"
                onClick={this.handleClear}
                aria-label={this.clearLabel}
              >
                <span aria-hidden="true">&times;</span>
              </button>
            )}
            <span class="suffix">
              <slot name="suffix" />
            </span>
          </div>
        </div>
        {showError && (
          <ds-text
            class="error-text"
            as="div"
            variant="text-body-small"
            color="negative"
            textId={this.errorId}
            role="alert"
          >
            {this.errorMessage}
          </ds-text>
        )}
      </Host>
    );
  }
}
